<template><section class="page"><header><div><h2>Prompt Playground</h2><p>Run a saved prompt version using your existing local model configuration.</p></div><div class="actions"><button @click="clearOutput">Clear Output</button><button class="primary" :disabled="running||!prompt" @click="run">{{running?'Running…':'Run'}}</button></div></header><div class="notice">Local data notice: variable values, rendered prompts and model outputs are stored in this browser's IndexedDB. API keys are never copied into PromptOps records.</div><div class="selectors"><label>Prompt<select v-model="selectedPromptId"><option value="">Select Prompt</option><option v-for="item in prompts" :key="item.id" :value="item.id">{{item.name}} · {{item.currentVersion}}</option></select></label><label>Version<select v-model="selectedVersionId"><option v-for="item in versions" :key="item.id" :value="item.id">{{item.versionNumber}}{{item.versionNumber===prompt?.currentVersion?' · Current':''}} · {{item.changeSummary}}</option></select></label></div><div v-if="notFound" class="error">Prompt or version not found.</div><div v-else class="columns"><div class="stack"><VariableInputPanel :variables="snapshot?.variables??[]" :values="values" @change="values=$event"/><article class="card"><h3>Rendered System Prompt</h3><pre>{{rendered.renderedSystemPrompt||'—'}}</pre><h3>Rendered User Prompt</h3><pre>{{rendered.renderedUserPrompt||'—'}}</pre><p v-for="item in rendered.diagnostics" :key="item.variable" class="error">{{item.message}}</p></article><article class="card"><h3>Model Configuration</h3><div class="config"><label>Provider<input v-model="model.provider"></label><label>Model<input v-model="model.modelName"></label><label>Temperature<input v-model.number="model.temperature" type="number" min="0" max="2" step=".1"></label><label>Max Tokens<input v-model.number="model.maxTokens" type="number"></label></div><button @click="useDefaults">Use Prompt Defaults</button><p class="muted">Streaming is enabled. Stop unavailable because the current shared LLMService has no unified Abort API.</p></article></div><div class="stack"><article class="card output"><h3>Model Output</h3><pre>{{output||'Output empty'}}</pre><p v-if="error" class="error">{{error}}</p><InvocationMetrics v-if="invocation" :invocation="invocation"/><div v-if="invocation"><p :class="invocation.outputValidation.valid?'ok':'error'">{{invocation.outputValidation.valid?'Output valid':'Output invalid'}}</p><RouterLink :to="`/invocations/${invocation.id}`">Open Invocation Detail</RouterLink></div></article><article class="card"><h3>Recent Invocations</h3><p v-if="!recent.length" class="muted">No invocations yet.</p><RouterLink v-for="item in recent" :key="item.id" :to="`/invocations/${item.id}`" class="history"><span>{{item.promptName}}</span><b>{{item.status}}</b><small>{{item.createdAt}}</small></RouterLink><RouterLink to="/invocations">View all</RouterLink></article></div></div></section></template>
<script setup lang="ts">
import{computed,onMounted,reactive,ref,watch}from'vue';import{RouterLink,useRoute,useRouter}from'vue-router';import type{ModelInvocation,PromptOpsPrompt as Prompt,PromptOpsPromptVersion as PromptVersion}from'@prompt-optimizer/core';import{renderPrompt}from'@prompt-optimizer/core';import{usePromptOpsServices}from'../../services/promptops';import{usePromptOpsUiStore}from'../../stores/promptops/usePromptOpsUiStore';import VariableInputPanel from'../../components/promptops/playground/VariableInputPanel.vue';import InvocationMetrics from'../../components/promptops/playground/InvocationMetrics.vue';
const route=useRoute(),router=useRouter(),services=usePromptOpsServices(),store=usePromptOpsUiStore();const prompts=ref<Prompt[]>([]),versions=ref<PromptVersion[]>([]),prompt=ref<Prompt>(),snapshot=ref<Prompt|PromptVersion>(),selectedPromptId=ref(''),selectedVersionId=ref(''),values=ref<Record<string,unknown>>({}),output=ref(''),error=ref(''),running=ref(false),invocation=ref<ModelInvocation>(),recent=ref<ModelInvocation[]>([]),notFound=ref(false);const model=reactive({provider:'',modelName:'',temperature:.7,maxTokens:1000});const rendered=computed(()=>snapshot.value?renderPrompt({systemPrompt:snapshot.value.systemPrompt,userPrompt:snapshot.value.userPrompt,variables:snapshot.value.variables,values:values.value}):{renderedSystemPrompt:'',renderedUserPrompt:'',diagnostics:[],valid:false});
const reset=()=>{values.value={};output.value='';error.value='';invocation.value=undefined};const useDefaults=()=>{if(snapshot.value)Object.assign(model,{provider:snapshot.value.modelProvider,modelName:snapshot.value.modelName,temperature:snapshot.value.temperature,maxTokens:snapshot.value.maxTokens})};const loadRecent=async()=>{recent.value=(await services.invocationRepository.list({workspaceId:store.currentWorkspaceId,promptId:selectedPromptId.value||undefined,limit:5})).items};
watch(selectedPromptId,async id=>{reset();prompt.value=id?await services.promptRepository.getById(id):undefined;notFound.value=Boolean(id&&!prompt.value);versions.value=id?await services.promptVersionRepository.listByPromptId(id):[];selectedVersionId.value=String(route.params.versionId||versions.value.find(x=>x.versionNumber===prompt.value?.currentVersion)?.id||versions.value[0]?.id||'');if(id&&String(route.params.promptId||'')!==id)await router.replace(`/playground/${id}`);await loadRecent()});watch(selectedVersionId,async id=>{reset();snapshot.value=id?await services.promptVersionRepository.getById(id):prompt.value;notFound.value=Boolean(id&&!snapshot.value);if(snapshot.value){values.value=Object.fromEntries(snapshot.value.variables.filter(x=>!x.unused).map(x=>[x.name,x.defaultValue??'']));useDefaults()}});
const run=async()=>{if(!snapshot.value||running.value)return;if(!rendered.value.valid){error.value='Failed to render prompt';return}running.value=true;error.value='';output.value='';try{const result=await services.promptInvocationService.run({workspaceId:store.currentWorkspaceId,promptId:selectedPromptId.value,promptVersionId:selectedVersionId.value||undefined,variableValues:values.value,modelOverride:{...model,streaming:true}},progress=>output.value=progress.output);invocation.value=result.invocation;output.value=result.output}catch(cause){error.value=cause instanceof Error?cause.message:String(cause);const id=(cause as{invocationId?:string}).invocationId;if(id)invocation.value=await services.invocationRepository.getById(id)}finally{running.value=false;await loadRecent()}};const clearOutput=()=>{output.value='';error.value='';invocation.value=undefined};onMounted(async()=>{prompts.value=await services.promptRepository.list({workspaceId:store.currentWorkspaceId,sortBy:'name',sortDirection:'asc'});selectedPromptId.value=String(route.params.promptId||route.query.promptId||'')})
</script><style scoped>.page,.stack{display:grid;gap:16px}header{display:flex;justify-content:space-between;align-items:start}h2{margin:0}.actions{display:flex;gap:8px}button{padding:9px 14px;border:1px solid #cbd5e1;border-radius:7px;background:#fff;cursor:pointer}.primary{background:#2563eb;color:#fff}.notice{padding:11px;background:#eff6ff;color:#1e40af;border-radius:8px}.selectors,.config{display:grid;grid-template-columns:1fr 1fr;gap:12px}.selectors label,.config label{display:grid;gap:5px}.selectors select,.config input{padding:9px;border:1px solid #cbd5e1;border-radius:7px}.columns{display:grid;grid-template-columns:1fr 1fr;gap:16px}.card{padding:16px;border:1px solid #e5e7eb;border-radius:10px;background:#fff}.card h3{margin-top:0}.card pre{white-space:pre-wrap;word-break:break-word;min-height:50px}.output>pre{min-height:180px}.error{color:#b91c1c}.ok{color:#047857}.muted{color:#64748b}.history{display:grid;grid-template-columns:1fr auto;gap:4px;padding:9px 0;border-bottom:1px solid #e5e7eb;text-decoration:none;color:inherit}.history small{grid-column:1/3;color:#64748b}@media(max-width:900px){.columns{grid-template-columns:1fr}}</style>
